class Solution:
    def fractionToDecimal(self, n: int, d: int) -> str:
        if d == 0: return "Error"
        sign = '-' if (n < 0) ^ (d < 0) else ''
        n, d = abs(n), abs(d)
        q, r = divmod(n, d)
        res = sign + str(q)
        if r == 0: return res
        res += '.'
        pos = {}
        frac = []
        while r:
            if r in pos:
                i = pos[r]
                return res + ''.join(frac[:i]) + '(' + ''.join(frac[i:]) + ')'
            pos[r] = len(frac)
            frac.append(str(r * 10 // d))
            r = r * 10 % d
        return res + ''.join(frac)

