class Solution {
public:
    string fractionToDecimal(int n, int d) {
        if (d == 0) return "Error";
        string res;
        if ((long long)n * d < 0) res += '-';
        long long a = abs((long long)n), b = abs((long long)d);
        res += to_string(a / b);
        long long r = a % b;
        if (!r) return res;
        res += '.';
        unordered_map<long long,int> pos;
        string frac;
        while (r) {
            if (pos.count(r)) {
                return res + frac.substr(0, pos[r]) + "(" + frac.substr(pos[r]) + ")";
            }
            pos[r] = frac.size();
            frac += char('0' + r * 10 / b);
            r = r * 10 % b;
        }
        return res + frac;
    }
};

